// Generate dynamic view query for the dataset
const datasetId = $input.first().json.dataset_id;
const mapping = $input.first().json.column_mapping;

// 1. Build the SELECT clause with safe naming and fallback for empty headers
const selectClauses = Object.entries(mapping).map(([originalName, genericColumn]) => {
    // Sanitize: trim whitespace and provide a fallback if the header is empty
    const cleanName = (originalName && originalName.trim() !== "") 
        ? originalName.trim() 
        : `unnamed_${genericColumn}`;

    // Wrap names in double quotes to handle spaces and special characters
    return `${genericColumn} AS "${cleanName}"`;
});


// 2. Construct the "DROP and CREATE" statement
// Using DROP VIEW IF EXISTS is the only way to handle changing column names 
// or counts without triggering a Postgres schema error.
const sql = `
DROP VIEW IF EXISTS n8n_data.v_active_analysis;

CREATE VIEW n8n_data.v_active_analysis AS 
SELECT 
    ${selectClauses.join(',\n    ')}
FROM n8n_data.universal_datatable
WHERE dataset_id = '${datasetId}';
`;


return {
  view_update_sql: sql,
  dataset_id: datasetId,
  dataset_name: $input.first().json.dataset_name,
  dataset_summary: $input.first().json.dataset_summary
};

// 1. Safely access input data from the current node
const inputData = $input.first();
if (!inputData) return { status: 'error', message: 'No input received' };

const agentOutput = inputData.json;

// 2. Access external node data
const webhookTrigger = $('Webhook Trigger').first()?.json?.body || {};
const datasetNode = $('Get Dataset').first()?.json || {};

// 3. Target the AI Agent node specifically for intermediate steps
const agentNodeData = $('AI Agent').first()?.json || {};
const steps = agentNodeData.intermediateSteps;

// 4. Process steps with Vector Store optimized formatting
let processUsed = 'No process steps recorded.';

if (Array.isArray(steps) && steps.length > 0) {
  processUsed = steps.map((step, index) => {
    const tool = step.action?.tool || 'Internal Reasoning';
    const toolInput = step.action?.toolInput ? JSON.stringify(step.action.toolInput) : 'N/A';

    // Clean up observation (handles objects/arrays/strings)
    let observation = step.observation;
    if (typeof observation === 'object') {
      observation = JSON.stringify(observation, null, 2);
    }

    // Structured for RAG: Clear headers help the embedding model identify relationships
    return `### STEP ${index + 1}
[Tool Used]: ${tool}
[Input]: ${toolInput}
[Observation]: ${observation || 'No output recorded.'}`;
  }).join('\n\n---\n\n');
}

// 5. Return the final structured object
return {
  status: 'ok',
  result: agentOutput.output || 'No response generated',
  processUsed: processUsed,
  metadata: {
    model: webhookTrigger.model || 'unknown',
    datasetName: datasetNode.dataset_name || 'unknown',
    stepCount: Array.isArray(steps) ? steps.length : 0
  }
};
